import React from "react";

function About() {
  return (
    <div style={{ padding: "50px", color: "white", background: "black", height: "100vh" }}>
      <h1 style={{ color: "#00ff00" }}>About Our Dealership</h1>

      <p>
        Welcome to our Kawasaki Dealership. We specialize in providing premium Kawasaki bikes
        with top-notch performance, design, and technology. Our mission is to deliver an unmatched
        riding experience to every customer.
      </p>

      <p>
        Whether you're a speed enthusiast or a casual rider, we have the perfect bike for you.
        Visit us and experience the thrill of Kawasaki.
      </p>

      <p>
        By Ratul & Vansh
      </p>
    </div>
  );
}

export default About;
